from typing import Dict, Any
import grpc

class AuthorizationService(grpc.Servicer):
    def __init__(self):
        self.custom_headers = {}

    def CheckRequest(self, request, context):
        headers = dict(request.headers)
        for header in self.custom_headers:
            if header in headers:
                headers[header] = self._check_authorization(header, headers[header])

        return grpc.CheckResponse(headers=headers)

    def _check_authorization(self, header, value):
        # Make authorization decisions based on the value of the custom header
        if header == "custom-header":
            # If the header is "custom-header" and its value is "allowed", allow the request
            if value == "allowed":
                return grpc.CheckResponse.Result.ALLOWED
            else:
                # Otherwise, deny the request
                return grpc.CheckResponse.Result.DENIED

        # For any other headers, deny the request by default
        return grpc.CheckResponse.Result.DENIED